var b="url",c="款式归档操作_已完成_.html",d="generationDate",e=new Date(1781589193325.65),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="Water",s="PreVerStatus",t="page",u="packageId",v="1d976d263a2e4eab9ed2c94e4b6da921",w="type",x="Axure:Page",y="款式归档操作(已完成)",z="notes",A="annotations",B="fn",C="1",D="ownerId",E="59d141ce6bf84adb9951764ef6c738b1",F="label",G="归档时间：2022-04-12",H="说明",I="<p><span>归档创建的日期</span></p>",J="2",K="af0a76bacbfa4e5e9ea2a7aedd074af5",L="选项1",M="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">全部成衣</span><span>展示方式</span></p><p><span>1.所有单个成衣颜色的BOM下：以相同的 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#8080FF;\">来源、工段、裁片大类、物料名称、尺码规格信息、损耗、部位、备注、含税单价、供应商名称</span><span> 的去重后生成对应行</span></p><p><span>2.单个成衣颜色BOM下的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#8080FF;\">物料颜色</span><span>填充至上述对应行的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">成衣颜色表头</span><span>下的物料颜色</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.若单个成衣颜色下无该物料，无须填充，为空即可</span></p>",N="3",O="cb1c50eac3744fcd8d011ccfa2773524",P="导出",Q="<p><span>1.按钮权限：仅</span><span style=\"text-decoration:underline ;\">任务状态</span><span>为'已完成'时展示</span></p><p><span>2.导出文件</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.格式：word</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.名称：归档版本_款号_工艺单.docx</span></p><p><span>3.固定页眉：标题</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.'配置项特定'+工艺单</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.使用配置项system_config_COMPANY_NAME</span></p><p><span>4.固定页眉：款式信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.展示对应款基础信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.包含字段：版本(归档版本)、类型(归档类型)、导出日期、款号、款名、内部款号、款式图片</span></p><p><span>5.归档信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.归档尺码：若有多个，使用顿号拼接</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.归档颜色：若有多个，使用顿号拼接</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.归档说明</span></p><p><span>6.尺码表：取[尺寸表]中的</span><span style=\"text-decoration:underline ;\">尺码清单</span></p><p><span>7.工序表：取[工序工价]中的</span><span style=\"text-decoration:underline ;\">工序表</span></p><p><span>8.工艺要求：取[工艺要求]中各工段及包装要求中</span><span style=\"text-decoration:underline ;\">“富文本”的数据</span></p><p><span>9.BOM清单：取[物料信息]中的</span><span style=\"text-decoration:underline ;\">建档物料</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.根据系统配置项system_config_BOM_FORMAT取Bom3或BOM4的数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.清单数据源：根据首个归档成衣颜色、首个成衣尺码的BOM清单，成衣数量视为1；计算出的各物料的计划使用量。</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.排序要求</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c1.优先物料类型排序①面料②辅料</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c2.其次同一类型下，按照计算出来的“计划用量”从大到下顺序</span></p>",R="4",S="3536a03120a54b4c9c5ce6b999669a07",T="* 归档类型：",U="<p><span>数据源：数据字典[system_config_SAMPLE_NAME]</span></p>",V="5",W="409995510161430db1c219c61b8a3c68",X="确认",Y="<p><span>1.校验“归档类型”的必填；否则提示：请选择归档类型</span></p><p><span>2.校验“归档说明”的必填；否则提示：请填写归档说明</span></p><p><span>3.通过校验：修改对应字段</span></p>",Z="style",ba="baseStyle",bb="627587b6038d43cca051c114ac41ad32",bc="pageAlignment",bd="center",be="fill",bf="fillType",bg="solid",bh="color",bi=0xFFFFFFFF,bj="image",bk="imageAlignment",bl="near",bm="imageRepeat",bn="auto",bo="favicon",bp="sketchFactor",bq="0",br="colorStyle",bs="appliedColor",bt="fontName",bu="Applied Font",bv="borderWidth",bw="borderVisibility",bx="borderFill",by=0xFF797979,bz="cornerRadius",bA="cornerVisibility",bB="outerShadow",bC="on",bD=false,bE="offsetX",bF=5,bG="offsetY",bH="blurRadius",bI="spread",bJ="r"